import { HelpArticleContentFormat } from "@/lib/graphql/generated/types";

/**
 * Project a raw dashboard-preview row (operator-side `HelpArticle`) into
 * the visitor-shaped projection the article view consumes. Defensive on
 * every field — the preview row is loosely-typed operator JSON.
 */
export function fromPreview(raw: Record<string, unknown>) {
  const idsOf = (arr: unknown): unknown[] => (Array.isArray(arr) ? arr : []);
  return {
    id: String(raw._id ?? ""),
    title: typeof raw.title === "string" ? raw.title : "",
    excerpt: typeof raw.excerpt === "string" ? raw.excerpt : "",
    content: typeof raw.content === "string" ? raw.content : "",
    contentFormat:
      raw.contentFormat === HelpArticleContentFormat.HTML
        ? HelpArticleContentFormat.HTML
        : HelpArticleContentFormat.MARKDOWN,
    authors: idsOf(raw.authors)
      .filter((a): a is Record<string, unknown> => !!a && typeof a === "object")
      .map((a) => ({
        _id: String(a._id ?? ""),
        name: typeof a.name === "string" ? a.name : null,
        photo: a.photo as { url: string } | null | undefined,
      })),
    tags: idsOf(raw.tags)
      .filter((tg): tg is Record<string, unknown> => !!tg && typeof tg === "object")
      .map((tg) => ({
        _id: String(tg._id ?? ""),
        slug: typeof tg.slug === "string" ? tg.slug : "",
        label: typeof tg.label === "string" ? tg.label : "",
      })),
  };
}
