"use client";

import { useTranslations } from "next-intl";
import { useEffect, useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardBody } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  MessageSquareIcon,
  type MessageSquareIconHandle,
} from "@/components/widget/icons/animated";
import { getMockHelpArticles } from "@/dummy";
import { getVisitorToken } from "@/lib/apollo-client";
import { looksLikeHtml } from "@/lib/detect-html";
import { HelpArticleContentFormat, ReactionSurface } from "@/lib/graphql/generated/types";
import {
  useRecordVisitorHelpViewMutation,
  useVisitorHelpArticleQuery,
  useVisitorHelpRelatedQuery,
} from "@/lib/graphql/queries/generated/help.generated";
import { useArticleTitleSink } from "@/lib/use-article-title-sink";
import { DEMO_LOCALES, useDemoTranslator } from "@/lib/use-demo-translator";
import { useIconHover } from "@/lib/use-icon-hover";
import { useWidgetConfig } from "@/lib/use-widget-config";
import { useWidgetEnv } from "@/lib/use-widget-env";
import { cn } from "@/lib/utils";
import { ArticleBody } from "../article-body";
import { LanguageSelector } from "../language-selector";
import { ReactionBar } from "../reaction-bar";
import { fromPreview } from "./helpers";

interface HelpArticleViewProps {
  slug: string;
  locale: string;
  isDummy: boolean;
  onHandoff: () => void;
  /** Open another article by slug — used by the related-articles
   *  rail. Shell wires this to the same route swap the help-tab
   *  search results use, so back-nav lands on the index. */
  onOpenArticle?: (slug: string) => void;
  /** Open a locale variant of THIS article — used by the below-article
   *  language selector. Distinct from `onOpenArticle` because the
   *  visitor lookup is keyed on `slug` + `locale`, so the target
   *  locale must travel with the slug. */
  onOpenTranslation?: (slug: string, locale: string) => void;
  /** Title sink for the widget shell's sticky header. Called with
   *  the article title once data resolves, and with `null` on
   *  unmount to clear the header back to "Help". */
  onTitleResolved?: (title: string | null) => void;
}

/**
 * Article detail. Markdown body via `react-markdown` + `remark-gfm`,
 * view counter, unresolved handoff, feedback bar.
 *
 * Order matters (Day 6 feedback): **CTA first, feedback below**.
 * The visitor's primary next-step after reading is either "this
 * answered my question" (close) or "I need more help" — the CTA
 * leads them straight to the messenger. Feedback is a secondary,
 * passive ask underneath.
 *
 * Back button is rendered by the shell's sticky header.
 */
export function HelpArticleView({
  slug,
  locale,
  isDummy,
  onHandoff,
  onOpenArticle,
  onOpenTranslation,
  onTitleResolved,
}: HelpArticleViewProps) {
  const t = useTranslations("help");
  const tDemo = useTranslations("demo");
  const env = useWidgetEnv();
  const { config } = useWidgetConfig();
  const showRelated = config.messenger?.showRelatedHelpArticles ?? true;
  const showReactionCounts = config.messenger?.showReactionCounts ?? true;
  const ctaHover = useIconHover<MessageSquareIconHandle>();

  // Article-scoped language switch in demo mode. Defaults to the widget
  // locale; the below-article dropdown changes it WITHOUT touching the
  // widget's own locale — it just re-renders this article from the
  // chosen locale's demo bundle.
  const [demoLocale, setDemoLocale] = useState(locale);
  const demoT = useDemoTranslator(demoLocale, tDemo);

  // Preview-mode short-circuit — look up by slug in the dashboard's
  // prefetched articles. Bypasses the visitor query entirely so the
  // preview pane doesn't need dashboard-origin authorization.
  const previewArticle = useMemo(() => {
    if (isDummy) return null;
    const list = env.previewData?.helpArticles;
    if (!Array.isArray(list)) return null;
    return (
      (list.find((a) => a && typeof a === "object" && (a as { slug?: unknown }).slug === slug) as
        | Record<string, unknown>
        | undefined) ?? null
    );
  }, [env.previewData, isDummy, slug]);
  const hasPreview = !!previewArticle;

  const { data, loading } = useVisitorHelpArticleQuery({
    variables: { args: { slug, locale } },
    skip: isDummy || hasPreview,
  });

  const [recordView] = useRecordVisitorHelpViewMutation();

  const mockArticle = useMemo(
    () => (isDummy ? getMockHelpArticles(demoT).find((a) => a.slug === slug) : null),
    [isDummy, slug, demoT],
  );

  const article = isDummy
    ? mockArticle
      ? {
          id: mockArticle.id,
          title: mockArticle.title,
          excerpt: mockArticle.excerpt,
          content: mockArticle.contentMarkdown,
          contentFormat: HelpArticleContentFormat.MARKDOWN,
          authors: mockArticle.authors as {
            _id: string;
            name: string | null;
            photo?: { url: string } | null;
          }[],
          tags: mockArticle.tags,
          reactionCounts: null as Record<string, number> | null,
          // Demo: the article is shown in the currently-selected demo
          // locale; the switcher's options come from `DEMO_LOCALES`.
          locale: demoLocale,
          translations: [] as { locale: string; slug: string }[],
        }
      : null
    : hasPreview && previewArticle
      ? {
          ...fromPreview(previewArticle),
          reactionCounts:
            (previewArticle.reactionCounts as Record<string, number> | null | undefined) ?? null,
          // Dashboard preview loads one article — no translation set.
          locale,
          translations: [] as { locale: string; slug: string }[],
        }
      : data?.visitorHelpArticle
        ? {
            id: data.visitorHelpArticle._id,
            title: data.visitorHelpArticle.title,
            excerpt: data.visitorHelpArticle.excerpt ?? "",
            content: data.visitorHelpArticle.content,
            contentFormat: data.visitorHelpArticle.contentFormat,
            authors: data.visitorHelpArticle.authors,
            tags: data.visitorHelpArticle.tags,
            reactionCounts:
              (data.visitorHelpArticle.reactionCounts as
                | Record<string, number>
                | null
                | undefined) ?? null,
            locale: data.visitorHelpArticle.locale,
            translations: data.visitorHelpArticle.translations,
          }
        : null;

  // Related articles — BE-side overlap scoring (shared folder + tags
  // + ancestors). Dummy mode renders nothing here; visitors on
  // production sites get the rail under the body.
  const { data: relatedData } = useVisitorHelpRelatedQuery({
    // Active widget locale (not the article's) so related follows the
    // reader's language even on a fallback (default-locale) article.
    variables: { articleId: article?.id ?? "", limit: 5, locale },
    skip: isDummy || hasPreview || !article?.id || !showRelated,
  });
  const related = relatedData?.visitorHelpRelated ?? [];

  // Visitor's own reaction slotIndex (BE `viewerReaction`) — authoritative
  // highlight for the reaction bar. Only the real read carries it.
  const viewerReaction =
    isDummy || hasPreview ? null : (data?.visitorHelpArticle?.viewerReaction ?? null);
  // All locale variants of this article (self + translations) — a reaction
  // is per-group, so the reaction bar updates every variant's cache.
  const groupItemIds =
    !isDummy && !hasPreview && data?.visitorHelpArticle
      ? [
          data.visitorHelpArticle._id,
          ...(data.visitorHelpArticle.translations ?? []).map((tr) => tr._id),
        ]
      : article?.id
        ? [article.id]
        : [];

  useEffect(() => {
    // View tracking is best-effort + visitor-JWT-guarded. Skip it when
    // there's no session token (e.g. the `requireAuth` gate's empty
    // anonymous session) — firing it would 401 and trip the 401-recovery
    // into a needless re-handshake on every article open.
    if (isDummy || !article?.id || !getVisitorToken()) return;
    recordView({ variables: { articleId: article.id } }).catch(() => {});
  }, [article?.id, isDummy, recordView]);

  // Surface the title up to the widget shell's sticky header (swaps
  // "Help" → article name). See `useArticleTitleSink` for why the
  // mount/unmount ownership is the single source of truth. Called
  // before the loading/not-found early returns so the hook order is
  // stable across renders — it's a no-op while `article` is undefined.
  useArticleTitleSink(article?.title, onTitleResolved);

  // Help-side feedback now flows through the unified reactions
  // surface (`submitVisitorReaction`), wired by the reaction-bar
  // component below. The "I still need help" handoff stays — it's a
  // navigation action, not a vote — but no longer records an
  // unresolved event (removed from BE).
  const handleHandoff = () => onHandoff();

  if (!loading && !article) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center px-6 py-12">
        <Card>
          <CardBody className="py-8 text-center">
            <p className="text-sm font-semibold text-wx-fg">{t("articleNotFound")}</p>
          </CardBody>
        </Card>
      </div>
    );
  }

  if (!article) {
    // Article-shaped skeleton — title block + author meta line +
    // a handful of body lines. Mirrors the real article's spacing
    // (px-5 pt-5) so the layout doesn't jump when content arrives.
    // The `animate-pulse` Tailwind utility runs purely on opacity
    // (no transform, no layout), which keeps the loader cheap and
    // doesn't compete with the shell's route-slide animation.
    return <HelpArticleSkeleton />;
  }

  return (
    <ScrollArea className="flex-1">
      {/* Plain `<div>` — the shell's route slide already covers the
          enter animation for this view, and stacking a second
          opacity+translate keyframe on top thrashed the main thread
          during article navigation (the panel was also animating
          its width, the route was sliding, and *then* the body was
          fading — three concurrent timelines). The route slide is
          enough; the article reveal feels snappier without the
          extra Motion subscription. */}
      <div className="flex flex-col px-5 pt-5 pb-12">
        <h2 className="text-xl leading-tight font-bold text-wx-fg">{article.title}</h2>
        {article.authors.length > 0 && (
          <p className="mt-2 flex items-center gap-2 text-xs text-wx-fg-muted">
            <span className="flex -space-x-1.5">
              {article.authors.slice(0, 3).map((a) => (
                <span
                  key={a._id}
                  className="h-5 w-5 overflow-hidden rounded-full bg-wx-bg-elevated ring-1 ring-wx-bg"
                  aria-hidden="true"
                >
                  {a.photo?.url ? (
                    // biome-ignore lint/performance/noImgElement: tiny avatar, no LCP impact
                    <img src={a.photo.url} alt="" className="h-full w-full object-cover" />
                  ) : (
                    <span className="flex h-full w-full items-center justify-center text-[10px] font-semibold uppercase text-wx-fg-muted">
                      {(a.name ?? "?").charAt(0)}
                    </span>
                  )}
                </span>
              ))}
            </span>
            <span>
              {t("writtenBy", {
                names: article.authors
                  .map((a) => a.name ?? "")
                  .filter(Boolean)
                  .join(", "),
              })}
            </span>
          </p>
        )}
        {article.tags.length > 0 && (
          <div className="mt-2 flex flex-wrap gap-1">
            {article.tags.map((tag) => (
              <span
                key={tag._id}
                className="rounded-full bg-wx-bg-elevated px-2 py-0.5 text-[11px] font-medium text-wx-fg-muted"
              >
                {tag.label}
              </span>
            ))}
          </div>
        )}
        {article.excerpt && <p className="mt-2 mb-5 text-sm text-wx-fg-muted">{article.excerpt}</p>}
        <ArticleBody
          content={article.content}
          // BE-stamped `contentFormat` is the authoritative signal,
          // but TipTap-authored articles historically save as MARKDOWN
          // (the BE default) with HTML content. Fall back to shape
          // detection so those still render as rich HTML rather than
          // escaped tags.
          isHtml={
            article.contentFormat === HelpArticleContentFormat.HTML ||
            looksLikeHtml(article.content)
          }
          markdownMarginClass="mt-3"
        />

        {/* CTA first — primary next-step affordance. `shrink-0` +
          `min-h-12` because the article view is a flex-col with
          overflow-y-auto; without an explicit floor the lg size's
          `h-12` was getting compressed by flex-shrink as the prose
          + feedback bar pushed against it. The icon animates on
          the button's hover via `useIconHover`. */}
        <Button
          type="button"
          variant="solid"
          size="lg"
          className="mt-6 w-full shrink-0 min-h-12"
          onClick={handleHandoff}
          {...ctaHover.parentHandlers}
        >
          <MessageSquareIcon ref={ctaHover.iconRef} size={16} />
          <span>{t("unresolvedCta")}</span>
        </Button>

        {/* Reactions bar — operator-curated emoji palette via the
            new unified reactions surface. Defaults seed to 👍 /
            👎 with sentiment tags so the "Was this helpful?" UX
            remains out-of-the-box; operators can edit the palette
            in their Help reactions settings. */}
        {article.id && (
          <ReactionBar
            surface={ReactionSurface.HELP}
            itemId={article.id}
            reactionCounts={article.reactionCounts}
            viewerReaction={viewerReaction}
            groupItemIds={groupItemIds}
            isDummy={isDummy}
            showCounts={showReactionCounts}
            className="mt-4"
          />
        )}

        {/* Language switcher — published locale variants of this
            article. In demo mode it switches the article content in
            place (article-scoped, no widget locale change); in live mode
            it opens the chosen translation by slug + locale. Hidden when
            only one language exists. */}
        <LanguageSelector
          currentLocale={isDummy ? demoLocale : article.locale}
          locales={isDummy ? [...DEMO_LOCALES] : article.translations.map((tr) => tr.locale)}
          onSelect={
            isDummy
              ? (loc) => setDemoLocale(loc)
              : (loc) => {
                  const target = article.translations.find((tr) => tr.locale === loc);
                  if (target) onOpenTranslation?.(target.slug, target.locale);
                }
          }
          className="mt-6"
        />

        {showRelated && related.length > 0 && (
          <section className="mt-6">
            <p className="mb-2 text-xs font-semibold tracking-wide text-wx-fg-muted uppercase">
              {t("relatedTitle")}
            </p>
            <ul className="flex flex-col gap-1.5">
              {related.map((r) => (
                <li key={r._id}>
                  <button
                    type="button"
                    onClick={() => onOpenArticle?.(r.slug)}
                    className="flex w-full items-start gap-3 rounded-wx-lg bg-wx-bg-elevated px-3 py-2 text-left transition-colors hover:bg-wx-bg-elevated/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary"
                  >
                    <span
                      className="aspect-square w-10 shrink-0 rounded-wx-sm bg-cover bg-center"
                      style={
                        r.coverImageUrl?.url
                          ? { backgroundImage: `url(${r.coverImageUrl.url})` }
                          : {
                              background: "linear-gradient(135deg, #1e1f21, #121314)",
                            }
                      }
                      aria-hidden="true"
                    />
                    <span className="min-w-0 flex-1">
                      <span className="block truncate text-sm font-medium text-wx-fg">
                        {r.title}
                      </span>
                      {r.excerpt && (
                        <span className="line-clamp-1 block text-xs text-wx-fg-muted">
                          {r.excerpt}
                        </span>
                      )}
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          </section>
        )}
      </div>
    </ScrollArea>
  );
}

/**
 * Loading state — article-shaped skeleton blocks. The earlier
 * placeholder was a literal `…` glyph, which looked broken next to
 * the polished article body that arrives 200-500 ms later. This
 * version paints a 2-line title, an author-meta strip, and a small
 * stack of body lines using `animate-pulse` (opacity-only, no
 * layout work) so the loader stays cheap and visually previews
 * what's about to show up.
 */
function HelpArticleSkeleton() {
  return (
    <ScrollArea className="flex-1">
      <div className="flex flex-col px-5 pt-5 pb-12" aria-busy="true" aria-live="polite">
        {/* Title — two lines of varying width feels more "title-ish"
            than one tall block, and previews real article geometry. */}
        <div className="animate-pulse space-y-2.5">
          <div className="h-5 w-3/4 rounded-md bg-wx-bg-elevated" />
          <div className="h-5 w-1/2 rounded-md bg-wx-bg-elevated" />
        </div>
        {/* Author meta */}
        <div className="mt-4 flex items-center gap-2 animate-pulse">
          <div className="h-5 w-5 rounded-full bg-wx-bg-elevated" />
          <div className="h-3 w-32 rounded-md bg-wx-bg-elevated" />
        </div>
        {/* Body — eight thin lines of decaying width simulate
            paragraphs of varying length. */}
        <div className="mt-6 space-y-2.5 animate-pulse">
          {["w-full", "w-11/12", "w-10/12", "w-full", "w-9/12", "w-full", "w-11/12", "w-7/12"].map(
            (w, i) => (
              // biome-ignore lint/suspicious/noArrayIndexKey: static order-stable skeleton with duplicate width values — index is the only stable key
              <div key={i} className={cn("h-3 rounded-md bg-wx-bg-elevated", w)} />
            ),
          )}
        </div>
      </div>
    </ScrollArea>
  );
}
